joi_block.script:
triggered := false
if (all(#PresenceSensor #Hallway).presenceSensor_presence ==| true) {
if (triggered == false) {
all(#Light #ColorControl #Hallway).colorControl_setColor("purple")
        triggered = true
}
}
else {
triggered = false
}

